('business:4-6-working-with-suppliers:match:fb5c5cb5', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Procurement”?", "options": ["Ordering goods and services — the actual process of placing orders and procuring goods.", "A party that supplies goods and/or services to another business.", "The management of purchasing goods and services within a business.", "Receiving deliveries from suppliers — managing storage and access for delivery."]}'::jsonb, '{"answer": 2, "explain": "“Procurement” means: The management of purchasing goods and services within a business."}'::jsonb),
('business:4-6-working-with-suppliers:match:78d7d9b2', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Logistics”?", "options": ["The management of purchasing goods and services within a business.", "The management of the transportation and storage of goods from seller to buyer.", "A party that supplies goods and/or services to another business.", "Selecting suppliers who operate responsibly — paying fair wages, protecting workers, and using sustainable materials."]}'::jsonb, '{"answer": 1, "explain": "“Logistics” means: The management of the transportation and storage of goods from seller to buyer."}'::jsonb),
('business:4-6-working-with-suppliers:match:ffd17f12', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Supply Chain”?", "options": ["A system where materials or parts are delivered exactly when needed for production, minimising storage costs.", "The management of the transportation and storage of goods from seller to buyer.", "The chain of businesses involved in the production of a product and its delivery to the end user.", "The management of purchasing goods and services within a business."]}'::jsonb, '{"answer": 2, "explain": "“Supply Chain” means: The chain of businesses involved in the production of a product and its delivery to the end user."}'::jsonb),
('business:4-6-working-with-suppliers:match:586c6995', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Supplier”?", "options": ["The service a supplier provides to business customers to handle problems, faults, and enquiries.", "A system where materials or parts are delivered exactly when needed for production, minimising storage costs.", "A party that supplies goods and/or services to another business.", "The chain of businesses involved in the production of a product and its delivery to the end user."]}'::jsonb, '{"answer": 2, "explain": "“Supplier” means: A party that supplies goods and/or services to another business."}'::jsonb),
('business:4-6-working-with-suppliers:match:932edb3f', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Just-In-Time (JIT)”?", "options": ["Receiving deliveries from suppliers — managing storage and access for delivery.", "A system where materials or parts are delivered exactly when needed for production, minimising storage costs.", "Choosing suppliers — evaluating who can supply the goods, at what price, and with what level of quality.", "Identifying the goods and services a business needs to buy, influenced by season, fashion, and technology."]}'::jsonb, '{"answer": 1, "explain": "“Just-In-Time (JIT)” means: A system where materials or parts are delivered exactly when needed for production, minimising storage costs."}'::jsonb),
('business:4-6-working-with-suppliers:match:80c07117', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Ethical Sourcing”?", "options": ["The management of purchasing goods and services within a business.", "The service a supplier provides to business customers to handle problems, faults, and enquiries.", "Selecting suppliers who operate responsibly — paying fair wages, protecting workers, and using sustainable materials.", "The ability of a supplier to consistently deliver the right quantity and quality of goods on time."]}'::jsonb, '{"answer": 2, "explain": "“Ethical Sourcing” means: Selecting suppliers who operate responsibly — paying fair wages, protecting workers, and using sustainable materials."}'::jsonb),
('business:4-6-working-with-suppliers:match:d01b8690', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Reliability of Supply”?", "options": ["The ability of a supplier to consistently deliver the right quantity and quality of goods on time.", "Choosing suppliers — evaluating who can supply the goods, at what price, and with what level of quality.", "Ordering goods and services — the actual process of placing orders and procuring goods.", "The management of the transportation and storage of goods from seller to buyer."]}'::jsonb, '{"answer": 0, "explain": "“Reliability of Supply” means: The ability of a supplier to consistently deliver the right quantity and quality of goods on time."}'::jsonb),
('business:4-6-working-with-suppliers:match:4e09e62e', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Stage 1 of Procurement”?", "options": ["A party that supplies goods and/or services to another business.", "Identifying the goods and services a business needs to buy, influenced by season, fashion, and technology.", "The chain of businesses involved in the production of a product and its delivery to the end user.", "Receiving deliveries from suppliers — managing storage and access for delivery."]}'::jsonb, '{"answer": 1, "explain": "“Stage 1 of Procurement” means: Identifying the goods and services a business needs to buy, influenced by season, fashion, and technology."}'::jsonb),
('business:4-6-working-with-suppliers:match:8cd46852', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Stage 2 of Procurement”?", "options": ["Identifying the goods and services a business needs to buy, influenced by season, fashion, and technology.", "A certification awarded to suppliers who meet ethical and environmental standards for sustainable production.", "Choosing suppliers — evaluating who can supply the goods, at what price, and with what level of quality.", "The service a supplier provides to business customers to handle problems, faults, and enquiries."]}'::jsonb, '{"answer": 2, "explain": "“Stage 2 of Procurement” means: Choosing suppliers — evaluating who can supply the goods, at what price, and with what level of quality."}'::jsonb),
